import {useEffect, useRef, useState} from "react";
import {Slider} from "primereact/slider";
import {InputNumber, type InputNumberChangeEvent} from "primereact/inputnumber";
import {type FilterEl} from "../Filter";
import {isEqual} from "lodash";


const NumberFilterElement: FilterEl<{
    min: number;
    max: number;
    debounceFilterWaitTime: number;
    filterMode: 'enter' | 'debounce';
}> = ({min, max, debounceFilterWaitTime, filterMode, ...options}) => {
    const [value, setValue] = useState<number | null>(null);
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Sync external filter value → local state (important for reset / clear)
    useEffect(() => {
        if (options.filterModel && 'value' in options.filterModel) {
            const v = options.filterModel.value;
            setValue(typeof v === 'number' ? v : null);
        }
    }, [options.filterModel]);

    const applyFilter = (val: number | null) => {
        if (debounceRef.current) clearTimeout(debounceRef.current);
        options.filterApplyCallback(val);
    };

    const onInputChange = (event: InputNumberChangeEvent) => {
        const newValue = event.value ?? null;
        setValue(newValue);

        if (filterMode === 'debounce' && newValue !== null) {
            if (debounceRef.current) clearTimeout(debounceRef.current);
            debounceRef.current = setTimeout(() => {
                options.filterApplyCallback(newValue);
            }, debounceFilterWaitTime);
        }
    };

    useEffect(() => {
        return () => {
            if (debounceRef.current) clearTimeout(debounceRef.current);
        };
    }, []);

    return (
        <InputNumber
            id="filter-number"
            value={value}
            style={{width: '100%'}}
            min={min}
            max={max}
            onChange={onInputChange}
            onKeyDown={(e) => {
                if (e.key === 'Enter') applyFilter(value);
            }}
            onBlur={() => applyFilter(value)}
        />
    );
};

const RangeFilterElement: FilterEl<{ min: number; max: number }> = ({min, max, ...options}) => {
    const [value, setValue] = useState<[number, number]>([min, max]);

    useEffect(() => {
        if (options.filterModel && "value" in options.filterModel) {
            if (
                Array.isArray(options.filterModel.value) &&
                options.filterModel.value.length == 2
            ) {
                const v = options.filterModel.value;
                if (typeof v[0] == "number" && typeof v[1] === "number") {
                    setValue([v[0], v[1]]);
                }
            } else {
                if (!options.filterModel["value"] && !isEqual(value, [min, max])) {
                    setValue([min, max]);
                }
            }
        }
    }, [options.filterModel]);

    return (
        <div
            style={{
                display: "flex",
                flexDirection: "row",
                gap: 2,
                width: "100%",
                justifyContent: "space-between",
                alignItems: "center",
            }}
        >
            <span>{value ? value[0] : min}</span>
            <Slider
                value={value}
                style={{width: "90%", margin: "0 13px"}}
                onChange={(e) => {
                    const v = e.value;
                    Array.isArray(v) &&
                    setValue(v.sort((a, b) => a - b) as [number, number]);
                }}
                onSlideEnd={(event) => {
                    Array.isArray(event.value) &&
                    options.filterApplyCallback(
                        event.value.sort((a, b) => a - b),
                    );
                }}
                prefix={"%"}
                range
                min={min}
                max={max}
            />
            <span>{value ? value[1] : max}</span>
        </div>
    );
};

const SliderFilterElement: FilterEl<{
    min: number;
    max: number;
    debounceFilterWaitTime: number;
    filterMode: 'enter' | 'debounce';
}> = ({debounceFilterWaitTime, filterMode, ...options}) => {
    const isRange =
        typeof options.filterModel?.matchMode == "string" &&
        options.filterModel.matchMode == "between";

    if (isRange) {
        return <RangeFilterElement {...options} />;
    }
    return (
        <NumberFilterElement
            {...options}
            debounceFilterWaitTime={debounceFilterWaitTime}
            filterMode={filterMode}
        />
    );
};

export default SliderFilterElement;
